    /**
     * Кэш SVG иконок
     */
    private static $cache = [];
    
    /**
     * Получить SVG иконку по имени
     * 
     * @param string $name Имя иконки (copy, telegram, vk, whatsapp, email, phone, map-pin, etc.)
     * @param array $options Дополнительные атрибуты (width, height, class, style)
     * @return string
     */
    public static function get($name, $options = [])
    {
        $defaults = [
            'width' => 14,
            'height' => 14,
            'class' => 'svg-icon',
            'style' => '',
        ];
        
        $options = array_merge($defaults, $options);
        
        // Строим ключ для кэша
        $cacheKey = $name . '_' . md5(serialize($options));
        
        if (isset(self::$cache[$cacheKey])) {
            return self::$cache[$cacheKey];
        }
        
        $svg = self::getSvgContent($name);
        
        if (!$svg) {
            return '';
        }
        
        // Применяем атрибуты
        $svg = str_replace('width="14"', 'width="' . $options['width'] . '"', $svg);
        $svg = str_replace('height="14"', 'height="' . $options['height'] . '"', $svg);
        
        if ($options['class']) {
            $svg = str_replace('class="', 'class="' . $options['class'] . ' ', $svg);
        }
        
        if ($options['style']) {
            $svg = str_replace('style="', 'style="' . $options['style'] . ';', $svg);
        }
        
        self::$cache[$cacheKey] = $svg;
        
        return $svg;
    }
    
